228: func (ti *treeIndex) Equal(bi index) bool {
229: 	b := bi.(*treeIndex)
230: 
231: 	if ti.tree.Len() != b.tree.Len() {
232: 		return false
233: 	}
234: 
235: 	equal := true
236: 
237: 	ti.tree.Ascend(func(aki *keyIndex) bool {
238: 		bki, _ := b.tree.Get(aki)
239: 		if !aki.equal(bki) {
240: 			equal = false
241: 			return false
242: 		}
243: 		return true
244: 	})
245: 
246: 	return equal
247: }
248: 
249: func (ti *treeIndex) Insert(ki *keyIndex) {
250: 	ti.Lock()
251: 	defer ti.Unlock()
252: 	ti.tree.ReplaceOrInsert(ki)
253: }
