96: type watcherSet map[*watcher]struct{}
97: 
98: func (w watcherSet) add(wa *watcher) {
99: 	if _, ok := w[wa]; ok {
100: 		panic("add watcher twice!")
101: 	}
102: 	w[wa] = struct{}{}
103: }
104: 
105: func (w watcherSet) union(ws watcherSet) {
106: 	for wa := range ws {
107: 		w.add(wa)
108: 	}
109: }
110: 
111: func (w watcherSet) delete(wa *watcher) {
112: 	if _, ok := w[wa]; !ok {
113: 		panic("removing missing watcher!")
114: 	}
115: 	delete(w, wa)
116: }
117: 
118: type watcherSetByKey map[string]watcherSet
119: 
120: func (w watcherSetByKey) add(wa *watcher) {
121: 	set := w[string(wa.key)]
122: 	if set == nil {
123: 		set = make(watcherSet)
124: 		w[string(wa.key)] = set
125: 	}
126: 	set.add(wa)
127: }
128: 
129: func (w watcherSetByKey) delete(wa *watcher) bool {
130: 	k := string(wa.key)
131: 	if v, ok := w[k]; ok {
132: 		if _, ok := v[wa]; ok {
133: 			delete(v, wa)
134: 			if len(v) == 0 {
135: 				// remove the set; nothing left
136: 				delete(w, k)
137: 			}
138: 			return true
139: 		}
140: 	}
141: 	return false
142: }
