156: 	g := ki.findGeneration(atRev)
157: 	if g.isEmpty() {
158: 		return Revision{}, Revision{}, 0, ErrRevisionNotFound
159: 	}
160: 
161: 	n := g.walk(func(rev Revision) bool { return rev.Main > atRev })
162: 	if n != -1 {
163: 		return g.revs[n], g.created, g.ver - int64(len(g.revs)-n-1), nil
164: 	}
165: 
166: 	return Revision{}, Revision{}, 0, ErrRevisionNotFound
167: }
