169: // since returns revisions since the given rev. Only the revision with the
170: // largest sub revision will be returned if multiple revisions have the same
171: // main revision.
172: func (ki *keyIndex) since(lg *zap.Logger, rev int64) []Revision {
173: 	if ki.isEmpty() {
174: 		lg.Panic(
175: 			"'since' got an unexpected empty keyIndex",
176: 			zap.String("key", string(ki.key)),
177: 		)
178: 	}
179: 	since := Revision{Main: rev}
180: 	var gi int
181: 	// find the generations to start checking
182: 	for gi = len(ki.generations) - 1; gi > 0; gi-- {
183: 		g := ki.generations[gi]
184: 		if g.isEmpty() {
185: 			continue
186: 		}
187: 		if since.GreaterThan(g.created) {
188: 			break
189: 		}
190: 	}
191: 
192: 	var revs []Revision
193: 	var last int64
194: 	for ; gi < len(ki.generations); gi++ {
195: 		for _, r := range ki.generations[gi].revs {
196: 			if since.GreaterThan(r) {
197: 				continue
198: 			}
199: 			if r.Main == last {
200: 				// replace the revision with a new one that has higher sub value,
201: 				// because the original one should not be seen by external
202: 				revs[len(revs)-1] = r
203: 				continue
204: 			}
205: 			revs = append(revs, r)
206: 			last = r.Main
207: 		}
208: 	}
209: 	return revs
210: }
