212: // compact compacts a keyIndex by removing the versions with smaller or equal
213: // revision than the given atRev except the largest one.
214: // If a generation becomes empty during compaction, it will be removed.
215: func (ki *keyIndex) compact(lg *zap.Logger, atRev int64, available map[Revision]struct{}) {
216: 	if ki.isEmpty() {
217: 		lg.Panic(
218: 			"'compact' got an unexpected empty keyIndex",
219: 			zap.String("key", string(ki.key)),
220: 		)
221: 	}
222: 
223: 	genIdx, revIndex := ki.doCompact(atRev, available)
224: 
225: 	g := &ki.generations[genIdx]
226: 	if !g.isEmpty() {
227: 		// remove the previous contents.
228: 		if revIndex != -1 {
229: 			g.revs = g.revs[revIndex:]
230: 		}
231: 	}
232: 
233: 	// remove the previous generations.
234: 	ki.generations = ki.generations[genIdx:]
235: }
