237: // keep finds the revision to be kept if compact is called at given atRev.
238: func (ki *keyIndex) keep(atRev int64, available map[Revision]struct{}) {
239: 	if ki.isEmpty() {
240: 		return
241: 	}
242: 
243: 	genIdx, revIndex := ki.doCompact(atRev, available)
244: 	g := &ki.generations[genIdx]
245: 	if !g.isEmpty() {
246: 		// If the given `atRev` is a tombstone, we need to skip it.
247: 		//
248: 		// Note that this s different from the `compact` function which
249: 		// keeps tombstone in such case. We need to stay consistent with
250: 		// existing versions, ensuring they always generate the same hash
251: 		// values.
252: 		if revIndex == len(g.revs)-1 && genIdx != len(ki.generations)-1 {
253: 			delete(available, g.revs[revIndex])
254: 		}
255: 	}
256: }
