258: func (ki *keyIndex) doCompact(atRev int64, available map[Revision]struct{}) (genIdx int, revIndex int) {
259: 	// walk until reaching the first revision smaller or equal to "atRev",
260: 	// and add the revision to the available map
261: 	f := func(rev Revision) bool {
262: 		if rev.Main <= atRev {
263: 			available[rev] = struct{}{}
264: 			return false
265: 		}
266: 		return true
267: 	}
268: 
269: 	genIdx, g := 0, &ki.generations[0]
270: 	// find first generation includes atRev or created after atRev
271: 	for genIdx < len(ki.generations)-1 {
272: 		if tomb := g.revs[len(g.revs)-1].Main; tomb >= atRev {
273: 			break
274: 		}
275: 		genIdx++
276: 		g = &ki.generations[genIdx]
277: 	}
278: 
279: 	revIndex = g.walk(f)
280: 
281: 	return genIdx, revIndex
282: }
